import{_ as s,o as i,c as t,ae as e}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"macOS 개발 설정","description":"OpenClaw macOS 앱 작업을 위한 개발자 설정 가이드","frontmatter":{"title":"macOS 개발 설정","description":"OpenClaw macOS 앱 작업을 위한 개발자 설정 가이드"},"headers":[],"relativePath":"platforms/mac/dev-setup.md","filePath":"platforms/mac/dev-setup.md","lastUpdated":null}'),n={name:"platforms/mac/dev-setup.md"};function l(p,a,o,h,r,c){return i(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="macos-개발자-설정" tabindex="-1">macOS 개발자 설정 <a class="header-anchor" href="#macos-개발자-설정" aria-label="Permalink to &quot;macOS 개발자 설정&quot;">​</a></h1><p>이 가이드는 소스에서 OpenClaw macOS 애플리케이션을 빌드하고 실행하는 데 필요한 단계를 다룹니다.</p><h2 id="사전-요구-사항" tabindex="-1">사전 요구 사항 <a class="header-anchor" href="#사전-요구-사항" aria-label="Permalink to &quot;사전 요구 사항&quot;">​</a></h2><p>앱을 빌드하기 전에 다음이 설치되어 있는지 확인하십시오:</p><ol><li><strong>Xcode 26.2+</strong>: Swift 개발에 필요합니다.</li><li><strong>Node.js 24 &amp; pnpm</strong>: 게이트웨이, CLI, 패키징 스크립트에 권장됩니다. 호환성을 위해 현재 <code>22.14+</code>인 Node 22 LTS도 지원됩니다.</li></ol><h2 id="_1-종속성-설치" tabindex="-1">1. 종속성 설치 <a class="header-anchor" href="#_1-종속성-설치" aria-label="Permalink to &quot;1. 종속성 설치&quot;">​</a></h2><p>프로젝트 전체 종속성을 설치합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h2 id="_2-앱-빌드-및-패키징" tabindex="-1">2. 앱 빌드 및 패키징 <a class="header-anchor" href="#_2-앱-빌드-및-패키징" aria-label="Permalink to &quot;2. 앱 빌드 및 패키징&quot;">​</a></h2><p>macOS 앱을 빌드하고 <code>dist/OpenClaw.app</code>으로 패키징하려면 다음을 실행하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/package-mac-app.sh</span></span></code></pre></div><p>Apple Developer ID 인증서가 없는 경우 스크립트가 자동으로 <strong>애드혹 서명</strong> (<code>-</code>)을 사용합니다.</p><p>개발 실행 모드, 서명 플래그, Team ID 문제 해결은 macOS 앱 README를 참조하십시오: <a href="https://github.com/openclaw/openclaw/blob/main/apps/macos/README.md" target="_blank" rel="noreferrer">https://github.com/openclaw/openclaw/blob/main/apps/macos/README.md</a></p><blockquote><p><strong>참고</strong>: 애드혹 서명된 앱은 보안 프롬프트를 트리거할 수 있습니다. 앱이 &quot;Abort trap 6&quot;으로 즉시 충돌하면 <a href="#문제-해결">문제 해결</a> 섹션을 참조하십시오.</p></blockquote><h2 id="_3-cli-설치" tabindex="-1">3. CLI 설치 <a class="header-anchor" href="#_3-cli-설치" aria-label="Permalink to &quot;3. CLI 설치&quot;">​</a></h2><p>macOS 앱은 백그라운드 작업을 관리하기 위해 전역 <code>openclaw</code> CLI 설치를 기대합니다.</p><p><strong>설치하려면 (권장):</strong></p><ol><li>OpenClaw 앱을 엽니다.</li><li><strong>General</strong> 설정 탭으로 이동합니다.</li><li>**&quot;Install CLI&quot;**를 클릭합니다.</li></ol><p>또는 수동으로 설치:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p><code>pnpm add -g openclaw@&lt;version&gt;</code>과 <code>bun add -g openclaw@&lt;version&gt;</code>도 작동합니다. 게이트웨이 런타임은 Node가 권장 경로로 유지됩니다.</p><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><h3 id="빌드-실패-툴체인-또는-sdk-불일치" tabindex="-1">빌드 실패: 툴체인 또는 SDK 불일치 <a class="header-anchor" href="#빌드-실패-툴체인-또는-sdk-불일치" aria-label="Permalink to &quot;빌드 실패: 툴체인 또는 SDK 불일치&quot;">​</a></h3><p>macOS 앱 빌드는 최신 macOS SDK와 Swift 6.2 툴체인을 기대합니다.</p><p><strong>시스템 종속성 (필수):</strong></p><ul><li><strong>소프트웨어 업데이트에서 사용 가능한 최신 macOS 버전</strong> (Xcode 26.2 SDK에 필요)</li><li><strong>Xcode 26.2</strong> (Swift 6.2 툴체인)</li></ul><p><strong>확인:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xcodebuild</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xcrun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swift</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>버전이 일치하지 않으면 macOS/Xcode를 업데이트하고 빌드를 다시 실행하십시오.</p><h3 id="권한-부여-시-앱-충돌" tabindex="-1">권한 부여 시 앱 충돌 <a class="header-anchor" href="#권한-부여-시-앱-충돌" aria-label="Permalink to &quot;권한 부여 시 앱 충돌&quot;">​</a></h3><p><strong>음성 인식</strong> 또는 <strong>마이크</strong> 접근을 허용하려고 할 때 앱이 충돌하면 TCC 캐시가 손상되었거나 서명이 불일치할 수 있습니다.</p><p><strong>수정:</strong></p><ol><li><p>TCC 권한 재설정:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tccutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> All</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ai.openclaw.mac.debug</span></span></code></pre></div></li><li><p>실패하면 macOS에서 &quot;깨끗한 슬레이트&quot;를 강제하기 위해 <a href="https://github.com/openclaw/openclaw/blob/main/scripts/package-mac-app.sh" target="_blank" rel="noreferrer"><code>scripts/package-mac-app.sh</code></a>에서 <code>BUNDLE_ID</code>를 임시로 변경하십시오.</p></li></ol><h3 id="게이트웨이-starting-상태-지속" tabindex="-1">게이트웨이 &quot;Starting...&quot; 상태 지속 <a class="header-anchor" href="#게이트웨이-starting-상태-지속" aria-label="Permalink to &quot;게이트웨이 &quot;Starting...&quot; 상태 지속&quot;">​</a></h3><p>게이트웨이 상태가 &quot;Starting...&quot;에 머물러 있으면 좀비 프로세스가 포트를 점유하고 있는지 확인하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># LaunchAgent를 사용하지 않는 경우 (개발 모드 / 수동 실행), 리스너 찾기:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsof</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -nP</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -iTCP:18789</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sTCP:LISTEN</span></span></code></pre></div><p>수동 실행이 포트를 점유하고 있으면 해당 프로세스를 중지하십시오 (Ctrl+C). 최후 수단으로 위에서 찾은 PID를 종료하십시오.</p>`,37)])])}const g=s(n,[["render",l]]);export{k as __pageData,g as default};
